if (nivel <= 25) alerta = "🔴 CRÍTICO";
else if (nivel <= 50) alerta = "🟡 ATENÇÃO";
else alerta = "🟢 NORMAL";

// --- LÓGICA DE NOTIFICAÇÃO ---
let notificacao = null;

if (nivel <= 25) {
    notificacao = {
        payload: `🚨 Nível Crítico ${NOME_BLOCO}: Verifique as boias!`,
        topic: "ALERTA",
        type: "error",
        displayMode: "toast"
    };
} else {
    notificacao = null;
}

// BOIA
let boiaTxt = (boia == 1) ? "🟢 ATIVA" : "🔴 DESLIGADA";

// SISTEMA (memória)
