let sistemaTxt = (sistema === "SYS_ON") ? "🟢 ATIVO" : "🔴 DESLIGADO";

// BOMBA (memória)
let comandoBomba = flow.get("bomba") || "BOMBA_OFF";

// REGRA FINAL
let bombaLigada = (comandoBomba === "BOMBA_ON") || (boia == 1);

let bombaTxt = bombaLigada
    ? "🟢 LIGADA"
    : "🔴 DESLIGADA";

return [
    { payload: nivel },
    { payload: alerta },
    { payload: boiaTxt },
    { payload: sistemaTxt },
    { payload: bombaTxt },
    { payload: nivel },
    notificacao
];

